"use client";

/**
 * /inbox — webmail list-detail screen, cold-built on @gunjo/ui@0.0.1-alpha.2.
 *
 * Library components composed here:
 *   Sidebar shell (SidebarProvider/Sidebar/Body via FolderNav→SidebarItem),
 *   ResizablePanelGroup/ResizablePanel/ResizableHandle (desktop split),
 *   ScrollArea (independent pane scroll), SearchInput, Tabs (All/Unread filter),
 *   Checkbox + Toggle + Avatar + Badge (rows), Button/TooltipButton (toolbars),
 *   Sheet (mobile folder drawer), EmptyState, Skeleton.
 *
 * Hand-rolled (because the library has no primitive for it):
 *   - The selectable, keyboard-navigable message LIST (role="listbox" + roving
 *     focus + arrow keys). `List`/`ListItem` are presentational only — docs say
 *     so explicitly. This is the single biggest gap for an inbox.
 *   - The master-detail orchestration + mobile list↔detail swap. Nothing in the
 *     library expresses "two panes, swap on mobile".
 *
 * Responsive model:
 *   - lg+  : Resizable split — list | handle | detail, side by side.
 *   - <lg  : ONE pane at a time. List view; selecting a message swaps to detail
 *            with a Back button. Folders move into a left Sheet drawer.
 *
 * a11y: exactly one <h1> (sr-only app title). Subject in detail is <h2>.
 * Unread = bold + dot + sr-only "Unread" (never colour alone). All controls are
 * real labelled buttons. The Resizable handle is keyboard-operable (Radix/RRP).
 */

import * as React from "react";
import {
  IconMenu2,
  IconArchive,
  IconTrash,
  IconMailOpened,
  IconX,
  IconInbox,
} from "@tabler/icons-react";
import {
  ResizablePanelGroup,
  ResizablePanel,
  ResizableHandle,
  ScrollArea,
  SearchInput,
  Tabs,
  TabsList,
  TabsTrigger,
  Checkbox,
  Button,
  Separator,
  EmptyState,
  Sheet,
  SheetContent,
  SheetTitle,
  SheetDescription,
} from "@gunjo/ui";
import {
  MESSAGES,
  FOLDERS,
  type Message,
  type FolderId,
} from "./data";
import { MessageRow } from "./MessageRow";
import { MessageDetail } from "./MessageDetail";
import { FolderNav } from "./FolderNav";
import { ListSkeleton } from "./ListSkeleton";

type Filter = "all" | "unread";

/**
 * Tailwind `lg` breakpoint (1024px). We mount EITHER the desktop split OR the
 * mobile single-pane — never both — so the message list isn't duplicated in the
 * DOM (which would dupe row ids and confuse AT). SSR/first paint assumes desktop
 * to match the static prerender, then corrects on mount.
 */
function useIsDesktop() {
  const [isDesktop, setIsDesktop] = React.useState(true);
  React.useEffect(() => {
    const mq = window.matchMedia("(min-width: 1024px)");
    const update = () => setIsDesktop(mq.matches);
    update();
    mq.addEventListener("change", update);
    return () => mq.removeEventListener("change", update);
  }, []);
  return isDesktop;
}

export default function InboxPage() {
  const isDesktop = useIsDesktop();
  // ---- state ----
  const [messages, setMessages] = React.useState<Message[]>(MESSAGES);
  const [activeFolder, setActiveFolder] = React.useState<FolderId>("inbox");
  const [selectedId, setSelectedId] = React.useState<string | null>(null);
  const [checkedIds, setCheckedIds] = React.useState<Set<string>>(new Set());
  const [query, setQuery] = React.useState("");
  const [filter, setFilter] = React.useState<Filter>("all");
  const [loading, setLoading] = React.useState(true);
  const [mobileDetail, setMobileDetail] = React.useState(false);
  const [drawerOpen, setDrawerOpen] = React.useState(false);

  const rowRefs = React.useRef<Map<string, HTMLLIElement>>(new Map());

  // simulate initial list load (skeleton)
  React.useEffect(() => {
    const t = setTimeout(() => setLoading(false), 900);
    return () => clearTimeout(t);
  }, []);

  // ---- derived ----
  const unreadByFolder = React.useMemo(() => {
    const base = Object.fromEntries(
      FOLDERS.map((f) => [f.id, 0])
    ) as Record<FolderId, number>;
    for (const m of messages) {
      if (m.folder === "inbox" && !m.read) base.inbox += 1;
      if (m.starred && !m.read) base.starred += 1;
    }
    // drafts is a static placeholder count
    base.drafts = 2;
    return base;
  }, [messages]);

  const folderMessages = React.useMemo(() => {
    if (activeFolder === "starred") {
      return messages.filter((m) => m.starred);
    }
    return messages.filter((m) => m.folder === activeFolder);
  }, [messages, activeFolder]);

  const visibleMessages = React.useMemo(() => {
    const q = query.trim().toLowerCase();
    return folderMessages.filter((m) => {
      if (filter === "unread" && m.read) return false;
      if (!q) return true;
      return (
        m.fromName.toLowerCase().includes(q) ||
        m.subject.toLowerCase().includes(q) ||
        m.preview.toLowerCase().includes(q)
      );
    });
  }, [folderMessages, filter, query]);

  const selectedMessage =
    messages.find((m) => m.id === selectedId) ?? null;

  const unreadCount = folderMessages.filter((m) => !m.read).length;

  // ---- actions ----
  const openMessage = React.useCallback((id: string) => {
    setSelectedId(id);
    setMobileDetail(true);
    setMessages((prev) =>
      prev.map((m) => (m.id === id ? { ...m, read: true } : m))
    );
  }, []);

  const toggleStar = React.useCallback((id: string) => {
    setMessages((prev) =>
      prev.map((m) => (m.id === id ? { ...m, starred: !m.starred } : m))
    );
  }, []);

  const toggleCheck = React.useCallback((id: string, next: boolean) => {
    setCheckedIds((prev) => {
      const n = new Set(prev);
      if (next) n.add(id);
      else n.delete(id);
      return n;
    });
  }, []);

  const clearChecks = React.useCallback(() => setCheckedIds(new Set()), []);

  const allVisibleChecked =
    visibleMessages.length > 0 &&
    visibleMessages.every((m) => checkedIds.has(m.id));

  const toggleCheckAll = React.useCallback(
    (next: boolean) => {
      setCheckedIds((prev) => {
        const n = new Set(prev);
        for (const m of visibleMessages) {
          if (next) n.add(m.id);
          else n.delete(m.id);
        }
        return n;
      });
    },
    [visibleMessages]
  );

  const bulkMarkRead = React.useCallback(() => {
    setMessages((prev) =>
      prev.map((m) => (checkedIds.has(m.id) ? { ...m, read: true } : m))
    );
    clearChecks();
  }, [checkedIds, clearChecks]);

  const bulkArchive = React.useCallback(() => {
    setMessages((prev) =>
      prev.map((m) =>
        checkedIds.has(m.id) ? { ...m, folder: "archive" } : m
      )
    );
    if (selectedId && checkedIds.has(selectedId)) setSelectedId(null);
    clearChecks();
  }, [checkedIds, selectedId, clearChecks]);

  const bulkDelete = React.useCallback(() => {
    setMessages((prev) =>
      prev.map((m) =>
        checkedIds.has(m.id) ? { ...m, folder: "trash" } : m
      )
    );
    if (selectedId && checkedIds.has(selectedId)) setSelectedId(null);
    clearChecks();
  }, [checkedIds, selectedId, clearChecks]);

  const archiveOne = React.useCallback((id: string) => {
    setMessages((prev) =>
      prev.map((m) => (m.id === id ? { ...m, folder: "archive" } : m))
    );
    setSelectedId(null);
    setMobileDetail(false);
  }, []);

  const deleteOne = React.useCallback((id: string) => {
    setMessages((prev) =>
      prev.map((m) => (m.id === id ? { ...m, folder: "trash" } : m))
    );
    setSelectedId(null);
    setMobileDetail(false);
  }, []);

  const markUnreadOne = React.useCallback((id: string) => {
    setMessages((prev) =>
      prev.map((m) => (m.id === id ? { ...m, read: false } : m))
    );
  }, []);

  const selectFolder = React.useCallback((id: FolderId) => {
    setActiveFolder(id);
    setSelectedId(null);
    setMobileDetail(false);
    clearChecks();
    setDrawerOpen(false);
  }, [clearChecks]);

  // ---- keyboard list navigation (roving focus) ----
  const onRowKeyDown = React.useCallback(
    (e: React.KeyboardEvent<HTMLLIElement>) => {
      const ids = visibleMessages.map((m) => m.id);
      const current = (e.currentTarget.getAttribute("data-id") || "") as string;
      const idx = ids.indexOf(current);
      let nextIdx = -1;
      if (e.key === "ArrowDown") nextIdx = Math.min(idx + 1, ids.length - 1);
      else if (e.key === "ArrowUp") nextIdx = Math.max(idx - 1, 0);
      else if (e.key === "Home") nextIdx = 0;
      else if (e.key === "End") nextIdx = ids.length - 1;
      if (nextIdx >= 0) {
        e.preventDefault();
        const nextId = ids[nextIdx];
        rowRefs.current.get(nextId)?.focus();
      }
    },
    [visibleMessages]
  );

  const checkedCount = checkedIds.size;
  const activeFolderLabel =
    FOLDERS.find((f) => f.id === activeFolder)?.label ?? "受信トレイ";

  // ---- list pane (shared desktop + mobile) ----
  const listPane = (
    <div className="flex h-full min-h-0 flex-col bg-background">
      {/* list header: search + filter */}
      <div className="border-b border-border p-3">
        <div className="flex items-center gap-2">
          {/* mobile: open folder drawer */}
          <Button
            variant="outline"
            size="icon"
            className="lg:hidden"
            aria-label="フォルダを開く"
            onClick={() => setDrawerOpen(true)}
          >
            <IconMenu2 className="h-4 w-4" />
          </Button>
          <SearchInput
            value={query}
            onValueChange={setQuery}
            placeholder="メールを検索"
            aria-label="メールを検索"
            className="flex-1"
          />
        </div>

        <div className="mt-3 flex items-center justify-between gap-2">
          <Tabs
            value={filter}
            onValueChange={(v) => setFilter(v as Filter)}
            className="w-auto rounded-md border-0"
          >
            <TabsList className="min-h-8 bg-muted p-1">
              <TabsTrigger value="all" className="h-7 px-3 text-xs">
                すべて
              </TabsTrigger>
              <TabsTrigger value="unread" className="h-7 px-3 text-xs">
                未読
                {unreadCount > 0 && (
                  <span className="ml-1.5 rounded-full bg-primary px-1.5 text-[10px] font-semibold text-primary-foreground tabular-nums">
                    {unreadCount}
                  </span>
                )}
              </TabsTrigger>
            </TabsList>
          </Tabs>

          <span className="text-xs text-muted-foreground">
            {visibleMessages.length}件
          </span>
        </div>
      </div>

      {/* bulk-action toolbar — appears when rows are checked */}
      {checkedCount > 0 && (
        <div
          role="toolbar"
          aria-label="一括操作"
          className="flex flex-wrap items-center gap-x-1.5 gap-y-1 border-b border-border bg-secondary/60 px-3 py-2"
        >
          <Checkbox
            checked={allVisibleChecked}
            onCheckedChange={toggleCheckAll}
            aria-label="表示中のメールをすべて選択"
          />
          <span className="text-xs font-medium text-foreground">
            {checkedCount}件選択中
          </span>
          <Separator orientation="vertical" className="mx-1 h-5" />
          {/* labels collapse to icon-only below sm so the toolbar never
              overflows at 375px; aria-label keeps each button named. */}
          <Button
            variant="ghost"
            size="sm"
            className="gap-1.5 px-2"
            onClick={bulkArchive}
            aria-label="選択したメールをアーカイブ"
          >
            <IconArchive className="h-4 w-4" />
            <span className="hidden sm:inline">アーカイブ</span>
          </Button>
          <Button
            variant="ghost"
            size="sm"
            className="gap-1.5 px-2"
            onClick={bulkMarkRead}
            aria-label="選択したメールを既読にする"
          >
            <IconMailOpened className="h-4 w-4" />
            <span className="hidden sm:inline">既読にする</span>
          </Button>
          <Button
            variant="ghost"
            size="sm"
            className="gap-1.5 px-2 text-muted-foreground hover:text-destructive"
            onClick={bulkDelete}
            aria-label="選択したメールを削除"
          >
            <IconTrash className="h-4 w-4" />
            <span className="hidden sm:inline">削除</span>
          </Button>
          <Button
            variant="ghost"
            size="icon"
            className="ml-auto h-8 w-8"
            aria-label="選択を解除"
            onClick={clearChecks}
          >
            <IconX className="h-4 w-4" />
          </Button>
        </div>
      )}

      {/* the list itself */}
      <ScrollArea className="min-h-0 flex-1">
        {loading ? (
          <ListSkeleton />
        ) : visibleMessages.length === 0 ? (
          <div className="p-6">
            <EmptyState
              icon={<IconInbox className="h-6 w-6" />}
              title="メールはありません"
              description={
                query
                  ? "検索条件に一致するメールはありません。"
                  : filter === "unread"
                    ? "未読のメールはありません。すべて確認済みです。"
                    : "このフォルダは空です。"
              }
              className="border-none bg-transparent"
            />
          </div>
        ) : (
          <ul
            role="listbox"
            aria-label={`${activeFolderLabel}のメール`}
            className="outline-none"
          >
            {visibleMessages.map((m, i) => (
              <MessageRowWrapper
                key={m.id}
                message={m}
                selected={selectedId === m.id}
                checked={checkedIds.has(m.id)}
                tabbable={selectedId ? selectedId === m.id : i === 0}
                onOpen={() => openMessage(m.id)}
                onToggleStar={() => toggleStar(m.id)}
                onToggleCheck={(next) => toggleCheck(m.id, next)}
                onRowKeyDown={onRowKeyDown}
                registerRef={(el) => {
                  if (el) rowRefs.current.set(m.id, el);
                  else rowRefs.current.delete(m.id);
                }}
              />
            ))}
          </ul>
        )}
      </ScrollArea>
    </div>
  );

  return (
    <div className="flex h-screen min-h-0 flex-col bg-background text-foreground">
      {/* exactly ONE h1 on the page */}
      <h1 className="sr-only">受信トレイ</h1>

      {/* top app bar */}
      <header className="flex h-14 shrink-0 items-center gap-3 border-b border-border px-4">
        <span className="flex items-center gap-2 font-semibold tracking-tight">
          <IconInbox className="h-5 w-5 text-primary" aria-hidden />
          Gunjo Mail
        </span>
        <span className="ml-auto text-sm text-muted-foreground">
          {activeFolderLabel}
        </span>
      </header>

      {/* body — mount EITHER desktop split OR mobile single pane (never both) */}
      <div className="flex min-h-0 flex-1">
        {isDesktop ? (
          <>
            {/* desktop folder sidebar */}
            <aside className="w-60 shrink-0 border-r border-border bg-muted/30">
              <FolderNav
                activeFolder={activeFolder}
                unreadByFolder={unreadByFolder}
                onSelectFolder={selectFolder}
                onCompose={() => {}}
              />
            </aside>

            {/* desktop: resizable list|detail.
               NOTE / FINDING: react-resizable-panels v4 treats a BARE NUMBER
               `defaultSize`/`minSize`/`maxSize` as PIXELS, not percent.
               `maxSize={55}` capped the list pane at 55px. Percentages must be
               passed as STRINGS. The public docs list these as `number` with no
               pixel-vs-percent note. */}
            <div className="min-w-0 flex-1">
              <ResizablePanelGroup direction="horizontal" className="h-full">
                <ResizablePanel defaultSize="38%" minSize="28%" maxSize="55%">
                  {listPane}
                </ResizablePanel>
                <ResizableHandle withHandle />
                <ResizablePanel defaultSize="62%" minSize="40%">
                  <MessageDetail
                    message={selectedMessage}
                    onArchive={archiveOne}
                    onDelete={deleteOne}
                    onMarkUnread={markUnreadOne}
                  />
                </ResizablePanel>
              </ResizablePanelGroup>
            </div>
          </>
        ) : (
          /* mobile: single pane, swap list<->detail */
          <div className="min-w-0 flex-1">
            {mobileDetail && selectedMessage ? (
              <MessageDetail
                message={selectedMessage}
                onBack={() => setMobileDetail(false)}
                onArchive={archiveOne}
                onDelete={deleteOne}
                onMarkUnread={markUnreadOne}
              />
            ) : (
              listPane
            )}
          </div>
        )}
      </div>

      {/* mobile folder drawer (Sheet, left side) */}
      <Sheet open={drawerOpen} onOpenChange={setDrawerOpen}>
        <SheetContent side="left" className="w-72 p-0">
          <SheetTitle className="px-4 pt-4 text-base">フォルダ</SheetTitle>
          <SheetDescription className="sr-only">
            メールフォルダを切り替えます
          </SheetDescription>
          <FolderNav
            activeFolder={activeFolder}
            unreadByFolder={unreadByFolder}
            onSelectFolder={selectFolder}
            onCompose={() => setDrawerOpen(false)}
          />
        </SheetContent>
      </Sheet>
    </div>
  );
}

/**
 * Wrapper that injects a stable `data-id`/`id` onto the row li so the roving
 * keyboard handler can find neighbours, and forwards the registerRef.
 */
function MessageRowWrapper(
  props: React.ComponentProps<typeof MessageRow>
) {
  const { registerRef, message, ...rest } = props;
  return (
    <MessageRow
      {...rest}
      message={message}
      registerRef={(el) => {
        if (el) {
          el.setAttribute("data-id", message.id);
          el.id = `row-${message.id}`;
        }
        registerRef(el);
      }}
    />
  );
}

"use client";

/**
 * FolderNav — the folder list, composed from Sidebar's SidebarItem.
 *
 * SidebarItem (navigation/SidebarItem.tsx) was a great fit: it renders a real
 * <button> with aria-current="page", takes `icon` / `label` / `count` / `isActive`
 * / `onClick`. The `count` is the unread badge.
 *
 * a11y NOTE / FINDING: SidebarItem's `count` is rendered as a bare number span
 * with NO accessible context (no "N unread"). A screen reader hears "Inbox 4",
 * not "Inbox, 4 unread". We add an sr-only suffix via a wrapper label below so
 * the count isn't ambiguous.
 */

import * as React from "react";
import {
  IconInbox,
  IconStar,
  IconSend,
  IconFileText,
  IconArchive,
  IconTrash,
  IconPencilPlus,
} from "@tabler/icons-react";
import { SidebarItem, Button } from "@gunjo/ui";
import { FOLDERS, type FolderId } from "./data";

const FOLDER_ICONS: Record<FolderId, React.ReactNode> = {
  inbox: <IconInbox className="h-4 w-4" />,
  starred: <IconStar className="h-4 w-4" />,
  sent: <IconSend className="h-4 w-4" />,
  drafts: <IconFileText className="h-4 w-4" />,
  archive: <IconArchive className="h-4 w-4" />,
  trash: <IconTrash className="h-4 w-4" />,
};

interface FolderNavProps {
  activeFolder: FolderId;
  unreadByFolder: Record<FolderId, number>;
  onSelectFolder: (id: FolderId) => void;
  onCompose: () => void;
}

export function FolderNav({
  activeFolder,
  unreadByFolder,
  onSelectFolder,
  onCompose,
}: FolderNavProps) {
  return (
    <div className="flex h-full flex-col gap-2 p-2">
      <Button
        variant="default"
        className="w-full justify-start gap-2"
        onClick={onCompose}
      >
        <IconPencilPlus className="h-4 w-4" />
        新規作成
      </Button>

      <nav aria-label="メールフォルダ" className="flex flex-col gap-0.5">
        {FOLDERS.map((f) => {
          const count = unreadByFolder[f.id] || undefined;
          return (
            <div key={f.id} className="relative">
              <SidebarItem
                id={f.id}
                icon={FOLDER_ICONS[f.id]}
                label={f.label}
                count={count}
                isActive={activeFolder === f.id}
                onClick={() => onSelectFolder(f.id)}
                reserveChevronSpace={false}
              />
              {/* sr-only clarifier for the unread count badge */}
              {count ? (
                <span className="sr-only">未読 {count} 件</span>
              ) : null}
            </div>
          );
        })}
      </nav>
    </div>
  );
}

"use client";

/** Loading skeleton for the message list, built from @gunjo/ui Skeleton. */

import { Skeleton } from "@gunjo/ui";

export function ListSkeleton({ rows = 8 }: { rows?: number }) {
  return (
    <ul aria-busy="true" aria-label="メールを読み込み中" className="divide-y divide-border">
      {Array.from({ length: rows }).map((_, i) => (
        <li key={i} className="flex gap-3 px-3 py-3">
          <Skeleton shape="rectangle" className="mt-1 h-4 w-4 rounded-[4px]" />
          <Skeleton shape="circle" className="h-9 w-9" />
          <div className="min-w-0 flex-1 space-y-2">
            <div className="flex items-center justify-between gap-2">
              <Skeleton shape="text" className="h-3.5 w-28" />
              <Skeleton shape="text" className="h-3 w-10" />
            </div>
            <Skeleton shape="text" className="h-3.5 w-3/4" />
            <Skeleton shape="text" className="h-3 w-5/6" />
          </div>
        </li>
      ))}
    </ul>
  );
}

"use client";

/**
 * MessageRow — ONE selectable message row in the list.
 *
 * COLD-TEST FINDING (big one): @gunjo/ui ships no selectable/active list-row
 * primitive. `List`/`ListItem` (display/List.tsx) are presentational markers
 * only — the docs explicitly say "TODO or completion operations requiring
 * interaction should be designed as Checkbox or Toggle compositions" and
 * "List is ul/ol meaning, markers, spacing, static dividing lines". So the
 * row itself, its selected/active state, `aria-selected`, and keyboard nav are
 * all hand-rolled here. We DO compose Avatar / Badge / Checkbox / Toggle /
 * Tooltip from the library inside the row.
 *
 * a11y model: the list is a `role="listbox"` (in page.tsx) and each row is a
 * `role="option"` with `aria-selected`. The row is a real focusable element
 * (tabIndex managed by roving focus in the parent). Unread is conveyed by
 * (1) bold sender + subject, (2) a visible dot, AND (3) an sr-only "Unread"
 * label — never colour alone.
 */

import * as React from "react";
import { IconStar, IconStarFilled, IconPaperclip } from "@tabler/icons-react";
import {
  Avatar,
  AvatarFallback,
  Badge,
  Checkbox,
  Toggle,
  cn,
} from "@gunjo/ui";
import type { Message } from "./data";

interface MessageRowProps {
  message: Message;
  selected: boolean;
  checked: boolean;
  /** roving tabindex: only the active row is in the tab order */
  tabbable: boolean;
  onOpen: () => void;
  onToggleStar: () => void;
  onToggleCheck: (next: boolean) => void;
  registerRef: (el: HTMLLIElement | null) => void;
  onRowKeyDown: (e: React.KeyboardEvent<HTMLLIElement>) => void;
}

export function MessageRow({
  message,
  selected,
  checked,
  tabbable,
  onOpen,
  onToggleStar,
  onToggleCheck,
  registerRef,
  onRowKeyDown,
}: MessageRowProps) {
  const unread = !message.read;

  return (
    <li
      ref={registerRef}
      role="option"
      aria-selected={selected}
      tabIndex={tabbable ? 0 : -1}
      data-message-row
      onClick={onOpen}
      onKeyDown={(e) => {
        // Enter/Space open the message; arrows handled by parent.
        if (e.key === "Enter" || e.key === " ") {
          e.preventDefault();
          onOpen();
        }
        onRowKeyDown(e);
      }}
      className={cn(
        "group relative flex cursor-pointer gap-3 border-b border-border px-3 py-3 outline-none transition-colors",
        "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-inset",
        selected ? "bg-secondary" : "hover:bg-muted/60",
        unread && !selected && "bg-primary-subtle/30"
      )}
    >
      {/* unread accent bar */}
      <span
        aria-hidden
        className={cn(
          "absolute inset-y-0 left-0 w-0.5",
          unread ? "bg-primary" : "bg-transparent"
        )}
      />

      {/* checkbox — stop propagation so checking doesn't open the message */}
      <div
        className="flex items-start pt-0.5"
        onClick={(e) => e.stopPropagation()}
      >
        <Checkbox
          checked={checked}
          onCheckedChange={onToggleCheck}
          aria-label={`${message.fromName}さんからのメールを選択：${message.subject}`}
        />
      </div>

      <Avatar className="mt-0.5 h-9 w-9">
        <AvatarFallback className="text-xs">{message.initials}</AvatarFallback>
      </Avatar>

      <div className="min-w-0 flex-1">
        <div className="flex items-baseline gap-2">
          <span
            className={cn(
              "truncate text-sm",
              unread ? "font-semibold text-foreground" : "text-foreground"
            )}
          >
            {message.fromName}
          </span>
          {unread && <span className="sr-only">未読</span>}
          <span className="ml-auto shrink-0 text-xs text-muted-foreground tabular-nums">
            {message.time}
          </span>
        </div>

        <div className="mt-0.5 flex items-center gap-1.5">
          <span
            className={cn(
              "truncate text-sm",
              unread ? "font-semibold text-foreground" : "text-muted-foreground"
            )}
          >
            {message.subject}
          </span>
        </div>

        <p className="mt-0.5 truncate text-xs text-muted-foreground">
          {message.preview}
        </p>

        {(message.labels?.length || message.starred) && (
          <div className="mt-1.5 flex flex-wrap items-center gap-1">
            {message.labels?.map((l) => (
              <Badge key={l.text} as="span" variant={l.tone} className="h-4 px-2 text-[10px]">
                {l.text}
              </Badge>
            ))}
          </div>
        )}
      </div>

      {/* star toggle — real aria-pressed button via Toggle; stop propagation */}
      <div
        className="flex items-start pt-0.5"
        onClick={(e) => e.stopPropagation()}
      >
        <Toggle
          size="sm"
          pressed={message.starred}
          onPressedChange={onToggleStar}
          aria-label={message.starred ? "スターを外す" : "スターを付ける"}
          className="h-7 w-7 min-w-0 px-0 data-[state=on]:!bg-transparent"
        >
          {message.starred ? (
            <IconStarFilled className="h-4 w-4 text-warning" />
          ) : (
            <IconStar className="h-4 w-4 text-muted-foreground" />
          )}
        </Toggle>
      </div>
    </li>
  );
}
